const fs = require('fs');
const stream = fs.createReadStream('huge.log');
stream.on('data', chunk => console.log(chunk.length));

Dim stream As FileStream = New FileStream("huge.log", FileMode.Open)
Dim buffer As Byte() = New Byte(1024) {}
Dim bytesRead As Integer = stream.Read(buffer, 0, buffer.Length)

with open('huge.log', 'rb') as stream:
    while True:
        chunk = stream.read(1024)
        if not chunk:
            break
        print(len(chunk))

try (InputStream stream = new FileInputStream("huge.log")) {
    byte[] buffer = new byte[1024];
    int bytesRead;
    while ((bytesRead = stream.read(buffer)) != -1) {
        System.out.println(bytesRead);
    }
}
